func solve(s string) int64 {
	n := len(s)

	// We iterate i from 0 up to the midpoint index inclusive.
	// The midpoint index is floor((n - 1) / 2).
	limit := (n - 1) / 2

	for i := 0; i <= limit; i++ {
		j := n - i - 1

		// Since s consists of ASCII characters, byte comparison is sufficient.
		if s[i] == s[j] {
			// Since we iterate from i=0 upwards, the first match found 
			// is guaranteed to be the smallest index i.
			return int64(i)
		}
	}

	// No such index found.
	return -1
}

